import{_ as o,o as t,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"89. Overtime","description":"","frontmatter":{"title":"89. Overtime","eba":"Mental Health Services 2024-2028","topics":["hours","overtime","preliminary","definitions"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/89-overtime.md","filePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/89-overtime.md"}'),n={name:"ebas/mental-health/rpn-pen-mho/hours-of-work/89-overtime.md"};function i(s,e,l,p,h,m){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_89-overtime" tabindex="-1">89. Overtime <a class="header-anchor" href="#_89-overtime" aria-label="Permalink to &quot;89. Overtime&quot;">​</a></h1><p><strong>89.1</strong> Application</p><p><strong>(a)</strong> This clause does not apply to an Employee over the level of RPN5 if they are not undertaking direct clinical work.</p><p><strong>(b)</strong> An Employer may require an Employee to work ‘reasonable overtime’ at overtime rates and such an Employee will work overtime in accordance with such a requirement.</p><p><strong>89.2</strong> Overtime Definition</p><p><strong>(a)</strong> Overtime means work requested or directed by the Employer that is performed:</p><p><strong>(i)</strong> in excess of the ordinary hours prescribed at <a href="/eba/ebas/mental-health/rpn-pen-mho/hours-of-work/88-hours-of-work.html">clause 88</a> (Hours of Work), save for the exception at <a href="/eba/ebas/mental-health/common-terms/hours-of-work/37-daylight-saving.html">clause 37</a> relating to Daylight Savings; or</p><p><strong>(ii)</strong> in addition to the Employee’s rostered shift length; or</p><p><strong>(iii)</strong> where a break of at least eight hours has not been provided between successive shifts – for all work performed until a break of eight hours is provided; or</p><p><strong>(iv)</strong> as recall to duty, including recall on a public holiday.</p><p><strong>(b)</strong> Overtime is also provided at <a href="/eba/ebas/mental-health/rpn-pen-mho/hours-of-work/91-oncall-recall-non-catt.html">clauses 91</a> (On-call /Recall), 92 (CATT On-call/Recall Allowances) and 93 (10 Hour break between overtime/recall).</p><p><strong>89.3</strong> Overtime Penalty Rates</p><p><strong>(a)</strong> Overtime penalty rates are to be paid as follows:</p><p><strong>(i)</strong> Monday to Friday (inclusive) – time and half for the first two hours, double time thereafter; and</p><p><strong>(ii)</strong> Saturday and Sunday – double time; and</p><p><strong>(iii)</strong> Public Holidays – see <a href="/eba/ebas/mental-health/rpn-pen-mho/leave/98-public-holidays.html">clause 98</a> (Public Holidays).</p><p><strong>(b)</strong> When calculating overtime payments, each day or shift shall stand alone. Where a period of overtime worked commences on one day and finishes on another, the calculation of overtime will be treated as if the overtime took place in a single day or shift. Example: An Employee commences overtime at 10pm and it concludes at 2am. The Employee shall be paid time and a half for the first 2 hours (10pm to midnight) and double time thereafter (midnight to 2am).</p><p><strong>89.4</strong> Rest break during overtime An employee working overtime will take a paid rest break of 20 minutes after each four hours of overtime worked if required to continue to work after the rest break.</p><p><strong>89.5</strong> Reasonable overtime</p><p><strong>(a)</strong> In determining whether overtime is &quot;reasonable overtime&quot; for the purposes of subclause 89.1(b), the following must be taken into account:</p><p><strong>(i)</strong> any risk to Employee health and safety from working the additional hours</p><p><strong>(ii)</strong> the Employee&#39;s personal circumstances, including family responsibilities</p><p><strong>(iii)</strong> the needs of the workplace or enterprise in which the Employee is employed</p><p><strong>(iv)</strong> whether the Employee is entitled to receive overtime payments, penalty rates or other compensation for, or a level of remuneration that reflects an expectation of, working additional hours</p><p><strong>(v)</strong> any notice given by the Employer of any request or requirement to work the additional hours</p><p><strong>(vi)</strong> any notice given by the Employee of their intention to refuse to work the additional hours</p><p><strong>(vii)</strong> the usual patterns of work in the industry, or the part of an industry, in which the Employee works</p><p><strong>(viii)</strong> the nature of the Employee&#39;s role, and the Employee&#39;s level of responsibility; and</p><p><strong>(ix)</strong> any other relevant matter.</p><p><strong>(b)</strong> An Employee may refuse to work overtime, if the request is unreasonable.</p><p><strong>89.6</strong> Approval of Overtime</p><p><strong>(a)</strong> A request or direction made by the manager of the ward/team that an Employee work overtime is, for the purposes of this clause, a direction or request of the Employer regardless of whether clause 89.6(b) is complied with.</p><p><strong>(b)</strong> An Employer may create policies and procedures regarding the process the nurse in manager of the ward/team is required to undertake prior to approving overtime.</p><p><strong>89.7</strong> Time off instead of payment for overtime</p><p><strong>(a)</strong> An Employees may, with the consent of the Employer, elect to take time off in lieu of payment for overtime worked, for a period equivalent to the overtime worked, plus a period of time equivalent to the overtime penalty incurred. Time off in lieu of overtime will be taken at a time mutually agreed between the Employer and the Employee, provided that the accrual of such leave shall not extend beyond a 28- day period.</p><p><strong>(b)</strong> Where the time off is not taken within 28 days, the overtime worked will be paid in the next pay period.</p><p><strong>89.8</strong> Transport following overtime</p><p><strong>(a)</strong> Where an Employee finishes a period of overtime at a time when reasonable means of transport are not available for the Employee to return to their place of residence the Employer will provide adequate transport free of cost to the Employee, including the return journey where the Employee&#39;s vehicle remains at the workplace.</p><p><strong>(b)</strong> Where overtime is a result of a double shift, the provisions at subclause 89.9 below (Additional Provisions for Double Shifts) also apply.</p><p><strong>89.9</strong> Additional Provisions for Double Shifts</p><p><strong>(a)</strong> A double shift occurs where a non-casual Employee has worked 14 or more continuous hours (inclusive of any paid or unpaid breaks).</p><p><strong>(b)</strong> An Employee who works a double shift will be entitled to overtime for the time worked in addition to the Employee&#39;s rostered shift length in accordance with subclause 89.3.</p><p><strong>(c)</strong> If an Employee works a double shift (which should only occur in emergency circumstances) the following will apply to mitigate the risk of fatigue and clinical error:</p><p><strong>(i)</strong> allow paid breaks of at least 10 minutes’ duration in each two hours worked; and</p><p><strong>(ii)</strong> adequate transport will be provided free of cost to the Employee, including the return journey where the Employee’s vehicle remains at the workplace.</p><p>Plain language terms: OT, extra hours, time and a half, double time, additional hours.</p>',46)])])}const c=o(n,[["render",i]]);export{u as __pageData,c as default};
